	.SBTTL	BITBLTFBLTX	=	3FBLTY	=	3	; oprateurs (A)	; --------------BLTAID	=	0		; n'utilise pas la trameBLTAAND	=	1		; op <-- data AND trameBLTAOR	=	2		; op <-- data OR  trameBLTAXOR	=	3		; op <-- data XOR trameBLTANOT	=	4		; NOT dataBLTATR	=	5		; n'utilise que la trame	; oprateurs (B)	; --------------BLTBID	=	8		; ne relit pas l'cranBLTBAND	=	9		; cran <-- op AND cranBLTBOR	=	10		; cran <-- op OR  cranBLTBXOR	=	11		; cran <-- op XOR cranBLTBNOT	=	12		; NOT op;--------\; BITBLT  >;========/;	!--------!;	! trame  !;	!  8x8	 !---->-----!		!---------------!;	!--------!	    !	  !--<--!		!;			    !	  !	!		!;	!---------------!  (A)->-(B)	!     cran	!;	!		!   !	  !	!		!;	!     motif	!   !	  !-->--!		!;	!  quelconque	!   !		!---------------!;	!		!->-!;	!		!;	!		!;	!---------------!; in	D3	coordonnes x;y dbut;	D4	delta x;y;	D5	oprations (A) et (B);	A3	^description zone rectangulaire;	A4	^description zone trame 8x8;; use	D0	offset byte;	D1	8 moins offset byte;	D2	masque pour la premire partie;	D3	masque pour la deuxime partie;	D4	compteurs x-y;	D5	oprations (A) et (B);	D6	compteur trame en y;	D7	divers;	A0	adresse cran byte de gauche;	A1	adresse cran byte de droite;	A2	-;	A3	^data;	A4	^byte actuel de la trame;	A5	^dbut de la trame;	A6	-; out	-; mod	-BITBLT:	PUSHM.L	D0,D1,D2,D3,D4,D5,D6,D7,A0,A1,A2,A3,A4,A5; Calcul le pointeur dans l'cran au byte de gauche (qui sera; rempli compltement ou partiellement) et le pointeur au byte; de droite (qui sera rempli partiellement ou pas du tout).	LOAD.L	D0,D3	SR.W	D0,#3	SWAP.W	D0	SL.W	D0,#6	SR.L	D0,#6	LOAD.L	A0,#PAGEECR*PA*GE	ADD.L	A0,D0		; A0 <-- adresse dans l'cran	LOAD.L	A1,A0	ADD.L	A1,#H'400	; A1 <-- adresse byte  droite; Calcul l'offset dans le byte de gauche (0..7) et l'offset; dans le byte de droite (1..8).	LOAD.W	D0,D3	AND.W	D0,#7		; D0 <-- offset byte	LOAD.W	D1,#8	SUB.W	D1,D0		; D1 <-- 8 moins offset byte; Aligne verticalement le pointeur dans la trame, afin; d'obtenir des trames juxtaposes (et non chevauches).	LOAD.L	A5,A4		; A5 <-- ^dbut trame	SWAP.W	D3		; D3 <-- coordonne y	AND.L	D3,#(2^FBLTY)-1	ADD.L	A4,D3		; aligne ^trame	LOAD.W	D6,#2^FBLTY	SUB.W	D6,D3		; D6 <-- compteur trame y	SWAP.W	D4		; D4 <-- compteurs x-y; Bouche principale. Dessine toutes les tranches verticales.20$:	PUSHM.L	D6,A0,A1,A4	PUSH.W	D4		; sauve delta y; Calcul les masques pour la partie gauche et pour la partie; droite. Si la dernire tranche est dessine, les masques; permettent de ne pas dborder, mme si la dernire tranche; est partielle.	SWAP.W	D4		; D4 <-- y-x	LOAD.B	D2,(PC)+(D0)+30$ ; D2 <-- masque pour droite	LOAD.B	D3,D2	SUB.W	D4,D1		; diminue pour partie gauche	JUMPR,PL 22$		; si 1re partie entire => 22$	NEG.W	D4	OR.B	D2,(PC)+(D4)+35$ ; masque dernire tranche	SET.B	D3		; D3 <-- masque total	CLR.W	D4		; D4 <-- reste plus rien	JUMPR	40$22$:	NOT.B	D3		; D3 <-- masque pour gauche	SUB.W	D4,D0		; diminue pour partie droite	JUMPR,PL 40$		; si 2me partie entire => 40$	NEG.W	D4	ASR.B	D3,D4		; masque dernire tranche	CLR.W	D4		; D4 <-- reste plus rien	JUMPR	40$30$:	.B	B'00000000	.B	B'00000001	.B	B'00000011	.B	B'00000111	.B	B'00001111	.B	B'00011111	.B	B'00111111	.B	B'01111111	.B	B'11111111	.EVEN35$:	.B	B'00000000	.B	B'10000000	.B	B'11000000	.B	B'11100000	.B	B'11110000	.B	B'11111000	.B	B'11111100	.B	B'11111110	.B	B'11111111	.EVEN; Boucle secondaire. Dessine une tranche verticale.40$:	SWAP.W	D4		; D4 <-- x-y45$:	PUSH.W	D6; Mixage entre le data et la trame pour la partie gauche de la; tranche  dessiner.	TEST.L	D5:#BLTATR	; data existe ?	JUMPR,EQ 50$		; oui => 50$	LOAD.B	D6,(A4)		; D6 <-- trame	NOT.B	D2	AND.B	D6,D2		; masque partie gauche	NOT.B	D2	JUMPR	59$50$:	LOAD.B	D6,(A3)		; D6 <-- data	SL.B	D6,D0	TEST.L	D5:#BLTANOT	JUMPR,EQ 52$	NOT.B	D6		; post-opration (A) NOT52$:	NOT.B	D2	AND.B	D6,D2		; masque partie gauche	NOT.B	D2	TEST.L	D5:#BLTAID	JUMPR,NE 59$	LOAD.B	D7,(A4)		; D7 <-- trame	NOT.B	D2	AND.B	D7,D2		; masque partie gauche	NOT.B	D2	TEST.L	D5:#BLTAAND	JUMPR,NE 55$	TEST.L	D5:#BLTAOR	JUMPR,NE 54$	TEST.L	D5:#BLTAXOR	XOR.B	D6,D7		; opration (A) XOR	JUMPR	59$54$:	OR.B	D6,D7		; opration (A) OR	JUMPR	59$55$:	AND.B	D6,D7		; opration (A) AND59$:; Mixage entre le data(*)trame et l'cran pour la partie; gauche de la tranche  dessiner.	LOAD.B	D7,(A0)		; D7 <-- byte cran (x;y)	TEST.L	D5:#BLTBNOT	JUMPR,EQ 60$	NOT.B	D6		; post-opration (B) NOT	NOT.B	D2	AND.B	D6,D2	NOT.B	D260$:	TEST.L	D5:#BLTBID	JUMPR,NE 66$	TEST.L	D5:#BLTBAND	JUMPR,NE 65$	TEST.L	D5:#BLTBOR	JUMPR,NE 64$	TEST.L	D5:#BLTBXOR	XOR.B	D6,D7		; opration (B) XOR	JUMPR	69$64$:	OR.B	D6,D7		; opration (B) OR	JUMPR	69$65$:	OR.B	D6,D2	AND.B	D6,D7		; opration (B) AND	JUMPR	69$66$:	AND.B	D7,D2		; masque partie droite	OR.B	D6,D769$:	LOAD.B	(A0+),D6	; crit rsultat dans l'cran; Mixage entre le data et la trame pour la partie droite de la; tranche  dessiner.	TEST.L	D5:#BLTATR	; data existe ?	JUMPR,EQ 70$		; oui => 70$	LOAD.B	D6,(A4)		; D6 <-- trame	NOT.B	D3	AND.B	D6,D3		; masque partie gauche	NOT.B	D3	JUMPR	79$70$:	LOAD.B	D6,(A3)		; D6 <-- data	SR.B	D6,D1	TEST.L	D5:#BLTANOT	JUMPR,EQ 72$	NOT.B	D6		; post-opration (A) NOT72$:	NOT.B	D3	AND.B	D6,D3		; masque partie gauche	NOT.B	D3	TEST.L	D5:#BLTAID	JUMPR,NE 79$	LOAD.B	D7,(A4)		; D7 <-- trame	NOT.B	D3	AND.B	D7,D3		; masque partie droite	NOT.B	D3	TEST.L	D5:#BLTAAND	JUMPR,NE 75$	TEST.L	D5:#BLTAOR	JUMPR,NE 74$	TEST.L	D5:#BLTAXOR	XOR.B	D6,D7		; opration (A) XOR	JUMPR	79$74$:	OR.B	D6,D7		; opration (A) OR	JUMPR	79$75$:	AND.B	D6,D7		; opration (A) AND79$:; Mixage entre le data(*)trame et l'cran pour la partie; droite de la tranche  dessiner.	LOAD.B	D7,(A1)		; D7 <-- byte cran (x;y)	TEST.L	D5:#BLTBNOT	JUMPR,EQ 80$	NOT.B	D6		; post-opration (B) NOT	NOT.B	D3	AND.B	D6,D3	NOT.B	D380$:	TEST.L	D5:#BLTBID	JUMPR,NE 86$	TEST.L	D5:#BLTBAND	JUMPR,NE 85$	TEST.L	D5:#BLTBOR	JUMPR,NE 84$	TEST.L	D5:#BLTBXOR	XOR.B	D6,D7		; opration (B) XOR	JUMPR	89$84$:	OR.B	D6,D7		; opration (B) OR	JUMPR	89$85$:	OR.B	D6,D3	AND.B	D6,D7		; opration (B) AND	JUMPR	89$86$:	AND.B	D7,D3		; masque partie droite	OR.B	D6,D789$:	LOAD.B	(A1+),D6	; crit rsultat dans l'cran	POP.W	D6; Calculs pour pouvoir dessiner le byte suivant dans la tranche; verticale.	INC.L	A3		; A3 <-- ^data suivant	INC.L	A4		; A4 <-- ^suivant dans trame	DEC.W	D6		; dcompte trame en y	JUMPR,NE 90$	LOAD.W	D6,#2^FBLTY	LOAD.L	A4,A5		; A4 <-- ^dbut trame90$:	DEC.W	D4		; dcompte delta y	JUMPR,NE 45$	POP.W	D4		; restitue delta y	POPM.L	D6,A0,A1,A4; Calculs pour pouvoir dessiner la tranche suivante.	ADD.L	A0,#H'400	ADD.L	A1,#H'400	LOAD.L	D2,D4	SWAP.W	D2		; D2 <-- delta x	TEST.W	D2		; reste qq chose  dessiner ?	JUMPR,NE 20$		; oui => 20$	POPM.L	D0,D1,D2,D3,D4,D5,D6,D7,A0,A1,A2,A3,A4,A5	RET	.END